const getOffsetPoint = (origin: Vector, angle: number, fwd: number, lat: number) => {
    const rad = angle * (Math.PI / 180);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);
    return {
        x: origin.x + (fwd * cos - lat * sin),
        y: origin.y + (fwd * sin + lat * cos)
    };
};

