                     // Use True Form Voice
                     if (newIdx % 3 === 0) audio.play('trueFormVoice'); 
                }
            } else {
                // Wait for a bit then switch text or phase
                const elapsed = now - c.startTime;

                if (c.dialogueText === dialogue1 && elapsed > 4000) { // Longer read time
                     c.dialogueText = dialogue2;
                     c.dialogueIndex = 0;
                     c.startTime = now;
