                c.phase = 'outro';
                c.startTime = now;
            }
        } else if (c.phase === 'outro') {
            // Zoom out
            c.targetCamera = { x: ARENA_WIDTH/2, y: ARENA_HEIGHT/2, zoom: 1.0 };

            // Camera lerp handled below
