        // Camera Smoothing
        const lerp = 0.05;
        cam.x += (c.targetCamera.x - cam.x) * lerp;
        cam.y += (c.targetCamera.y - cam.y) * lerp;
        cam.zoom += (c.targetCamera.zoom - cam.zoom) * lerp;
